# ── 地理編碼快取 ─────────────────────────────────────────────
GEOCACHE_FILE = "geocache.json"

def load_geocache():
    if os.path.exists(GEOCACHE_FILE):
        with open(GEOCACHE_FILE, "r", encoding="utf-8") as f:
            return json.load(f)
    return {}

def save_geocache(cache):
    with open(GEOCACHE_FILE, "w", encoding="utf-8") as f:
        json.dump(cache, f, ensure_ascii=False, indent=2)

@st.cache_data(show_spinner=False)
def geocode_addresses(addresses: tuple):
    """
    批次地理編碼，使用 geopy Nominatim。
    結果快取到本地 JSON，避免重複呼叫。
    回傳 dict: {地址: (lat, lon) or None}
    """
    try:
        from geopy.geocoders import Nominatim
        from geopy.extra.rate_limiter import RateLimiter
    except ImportError:
        return {addr: None for addr in addresses}

    cache = load_geocache()
    geolocator = Nominatim(user_agent="hsinchu_pet_dashboard")
    geocode = RateLimiter(geolocator.geocode, min_delay_seconds=1.1)

    results = {}
    changed = False
    for addr in addresses:
        if not addr or addr in ("nan", ""):
            results[addr] = None
            continue
        if addr in cache:
            results[addr] = tuple(cache[addr]) if cache[addr] else None
            continue
        # 加上「新竹市」讓搜尋更精準
        query = addr if "新竹" in addr else f"新竹市{addr}"
        try:
            loc = geocode(query, timeout=10)
            if loc:
                results[addr] = (loc.latitude, loc.longitude)
                cache[addr] = [loc.latitude, loc.longitude]
            else:
                results[addr] = None
                cache[addr] = None
            changed = True
        except Exception:
            results[addr] = None
    if changed:
        save_geocache(cache)
    return results

