@st.cache_data
def load_data():
    base = os.path.dirname(os.path.abspath(__file__))
    for name in ['新竹市動物醫院開業執業(1).csv', '新竹市動物醫院開業執業 (1).csv',
                 '新竹市動物醫院開業執業_1_.csv', '新竹市動物醫院開業執業.csv']:
        path = os.path.join(base, name)
        if os.path.exists(path):
            df_hosp = pd.read_csv(path, encoding='utf-8-sig')
            break
    else:
        st.error("找不到動物醫院 CSV！"); st.stop()

    df_drug = pd.read_csv(os.path.join(base, '新竹市動物用藥品販賣機構.csv'), encoding='utf-8-sig')
    df_reg  = pd.read_csv(os.path.join(base, '新竹市寵物登記站.csv'), encoding='utf-8-sig')

    def extract_district(addr):
        if pd.isna(addr): return '未標示'
        for d in ['東區', '北區', '香山區']:
            if d in addr: return d
        road_map = {
            '西大路':'北區','水田街':'香山區','南大路':'香山區','四維路':'東區',
            '關東路':'東區','民權路':'北區','中華路四':'香山區','中華路五':'香山區',
            '北大路':'北區','金城':'香山區','竹光路':'香山區','公園路':'東區',
            '武陵路':'北區','光復路':'東區','經國路':'香山區','科園路':'香山區',
            '關新路':'香山區','忠孝路':'東區','東大路':'北區','境福街':'香山區',
            '武陵西':'香山區','海埔路':'香山區','金竹路':'香山區','牛埔路':'香山區',
            '埔頂路':'香山區','光華一街':'東區','延平路':'香山區','公道三路':'東區',
            '花園新城':'香山區','關新一街':'東區','民族路':'東區','東光路':'東區',
            '中華路二':'北區','自由路':'北區',
        }
        for road, dist in road_map.items():
            if road in addr: return dist
        return '其他'

    df_hosp['區域'] = df_hosp['機構地址'].apply(extract_district)
    reg_names = set(df_reg['名稱'].str.strip())
    df_hosp['是否為登記站'] = df_hosp['機構名稱'].str.strip().isin(reg_names)
    df_hosp['類別顯示'] = df_hosp['執照類別'].map({'獸醫師':'獸醫師','獸醫佐':'獸醫佐'})
    df_reg['區域'] = df_reg['住址'].apply(extract_district)
    df_drug['縣市別'] = '新竹市'
    hosp_names = set(df_hosp['機構名稱'].str.strip())
    df_reg['是否為醫院'] = df_reg['名稱'].str.strip().isin(hosp_names)
    df_reg['站點類型'] = df_reg['是否為醫院'].map({True:'動物醫院兼辦', False:'專屬登記站/其他'})
    return df_hosp, df_drug, df_reg

df_hosp, df_drug, df_reg = load_data()

